def solve(nums, target):
    left, right = 0, len(nums) - 1
    while left < right:
        total = nums[left] + nums[right]
        if total == target:
            return left, right
        if total < target:
            left += 1
        else:
            right -= 1
    return -1, -1

# Additional checks for pitfalls
def check_no_solution(nums, target):
    if not nums or len(nums) < 2:
        return True  # No solution possible if less than 2 numbers
    return False

def check_indices_not_reused(left, right):
    return left != right

# Updated solve function with checks
def solve_with_checks(nums, target):
    if check_no_solution(nums, target):
        return -1, -1

    left, right = 0, len(nums) - 1
    while left < right:
        total = nums[left] + nums[right]
        if total == target:
            if check_indices_not_reused(left, right):
                return left, right
        if total < target:
            left += 1
        else:
            right -= 1
    return -1, -1
